import{_ as s,o as e,c as i,a3 as t}from"./chunks/framework.DACwFHq9.js";const r=JSON.parse('{"title":"sudo 免密配置","description":"","frontmatter":{},"headers":[],"relativePath":"development/linux/basic/sudo/sudo.md","filePath":"development/linux/basic/sudo/sudo.md","lastUpdated":1780114960000}'),n={name:"development/linux/basic/sudo/sudo.md"};function d(o,a,l,p,h,c){return e(),i("div",null,[...a[0]||(a[0]=[t(`<h1 id="sudo-mian-mi-pei-zhi" tabindex="-1">sudo 免密配置 <a class="header-anchor" href="#sudo-mian-mi-pei-zhi" aria-label="Permalink to &quot;sudo 免密配置&quot;">​</a></h1><h2 id="cha-kan-dang-qian-yong-hu-sudo-quan-xian" tabindex="-1">查看当前用户 sudo 权限 <a class="header-anchor" href="#cha-kan-dang-qian-yong-hu-sudo-quan-xian" aria-label="Permalink to &quot;查看当前用户 sudo 权限&quot;">​</a></h2><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">sudo</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> -l</span></span></code></pre></div><p>输出示例：</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>User ubuntu may run the following commands on ubuntu:</span></span>
<span class="line"><span>    (ALL : ALL) ALL</span></span>
<span class="line"><span>    (ALL) NOPASSWD: ALL</span></span></code></pre></div><p><code>NOPASSWD: ALL</code> 表示当前用户可以免密码执行所有 sudo 命令。</p><h2 id="pei-zhi-mian-mi-sudo" tabindex="-1">配置免密 sudo <a class="header-anchor" href="#pei-zhi-mian-mi-sudo" aria-label="Permalink to &quot;配置免密 sudo&quot;">​</a></h2><div class="warning custom-block github-alert"><p class="custom-block-title">WARNING</p><p>免密 sudo 提升了便利性，但也降低了安全性。仅在个人开发机或可信任环境中使用。</p></div><h3 id="fang-fa-yizhi-jie-xiu-gai-sudoers-wen-jian" tabindex="-1">方法一：直接修改 sudoers 文件 <a class="header-anchor" href="#fang-fa-yizhi-jie-xiu-gai-sudoers-wen-jian" aria-label="Permalink to &quot;方法一：直接修改 sudoers 文件&quot;">​</a></h3><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">sudo</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> visudo</span></span></code></pre></div><p>添加一行：</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>&lt;username&gt; ALL=(ALL) NOPASSWD: ALL</span></span></code></pre></div><h3 id="fang-fa-erxin-zeng-du-li-pei-zhi-wen-jiantui-jian" tabindex="-1">方法二：新增独立配置文件（推荐） <a class="header-anchor" href="#fang-fa-erxin-zeng-du-li-pei-zhi-wen-jiantui-jian" aria-label="Permalink to &quot;方法二：新增独立配置文件（推荐）&quot;">​</a></h3><p>在 <code>/etc/sudoers.d/</code> 下创建独立配置文件，避免直接修改 <code>/etc/sudoers</code>：</p><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">sudo</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> visudo</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> -f</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> /etc/sudoers.d/</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">&lt;</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">usernam</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">e</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">&gt;</span></span></code></pre></div><p>写入：</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>&lt;username&gt; ALL=(ALL) NOPASSWD: ALL</span></span></code></pre></div><blockquote><p><code>/etc/sudoers.d/</code> 下的文件会自动被 <code>/etc/sudoers</code> 通过 <code>#includedir</code> 指令加载。</p></blockquote><h3 id="jin-dui-te-ding-ming-ling-mian-mi" tabindex="-1">仅对特定命令免密 <a class="header-anchor" href="#jin-dui-te-ding-ming-ling-mian-mi" aria-label="Permalink to &quot;仅对特定命令免密&quot;">​</a></h3><p>如果不想完全放开，可以只对特定命令免密：</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>&lt;username&gt; ALL=(ALL) NOPASSWD: /usr/bin/systemctl, /usr/bin/docker</span></span></code></pre></div><h2 id="yan-zheng" tabindex="-1">验证 <a class="header-anchor" href="#yan-zheng" aria-label="Permalink to &quot;验证&quot;">​</a></h2><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;"># 用 sudo 执行一个需要 root 权限的命令，不应提示输入密码</span></span>
<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">sudo</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> whoami</span></span>
<span class="line"><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;"># 输出: root</span></span></code></pre></div><h2 id="yuan-li" tabindex="-1">原理 <a class="header-anchor" href="#yuan-li" aria-label="Permalink to &quot;原理&quot;">​</a></h2><p><code>sudo</code> 的权限配置由 <code>/etc/sudoers</code> 和 <code>/etc/sudoers.d/</code> 共同控制。语法格式：</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>&lt;用户&gt; &lt;主机&gt;=(&lt;运行身份&gt;) &lt;标签&gt;: &lt;命令&gt;</span></span></code></pre></div><table tabindex="0"><thead><tr><th>字段</th><th>含义</th></tr></thead><tbody><tr><td><code>&lt;用户&gt;</code></td><td>适用此规则的用户名或 <code>%组名</code></td></tr><tr><td><code>ALL</code>（主机）</td><td>适用所有主机</td></tr><tr><td><code>(ALL)</code></td><td>可以切换到任意用户身份执行</td></tr><tr><td><code>NOPASSWD:</code></td><td>免密码标签</td></tr><tr><td><code>ALL</code>（命令）</td><td>允许执行所有命令</td></tr></tbody></table><blockquote><p><code>visudo</code> 会在保存时进行语法检查，防止错误的 sudoers 配置导致无法使用 sudo。始终使用 <code>visudo</code> 而非直接编辑文件。</p></blockquote>`,28)])])}const g=s(n,[["render",d]]);export{r as __pageData,g as default};
